import { BaseColorProps } from '@/type';
import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import ArrowRight from 'lucide-solid/icons/arrow-right';
import Check from 'lucide-solid/icons/check';
import { Accessor, Component, createMemo, For, JSX, mergeProps, Setter, Show } from 'solid-js';

// ─── Types ────────────────────────────────────────────────────────────────────

export type StepItem = {
  title?: JSX.Element;
  description?: JSX.Element;
  icon?: JSX.Element;
};

export type StepsProps = {
  type?: 'default' | 'navigation' | 'dot';
  color?: BaseColorProps;
  orientation?: 'horizontal' | 'vertical';
  total?: number;
  items?: StepItem[];
  current?: Accessor<number>;
  setCurrent?: Setter<number>;
  onChange?: (index: number) => void;
  disabled?: number[];
  activeIndex?: number[];
  class?: {
    root?: string;
    step?: string;
    icon?: string;
    title?: string;
    description?: string;
    connector?: string;
  };
};

// ─── Helpers ──────────────────────────────────────────────────────────────────

type StepStatus = 'active' | 'done' | 'upcoming' | 'disabled';

const getStepStatus = (
  index: number,
  current: number,
  disabled: number[],
  activeIndex?: number[],
): StepStatus => {
  if (disabled.includes(index)) return 'disabled';
  if (activeIndex?.includes(index)) return 'active';
  if (index === current) return 'active';
  if (index < current) return 'done';
  return 'upcoming';
};

// ─── StepIcon — reusable icon renderer ───────────────────────────────────────
// Renders: checkmark (done, no custom icon) | custom icon | step number

type StepIconProps = {
  index: number;
  status: StepStatus;
  icon?: JSX.Element;
  class?: string;
};

const StepIconContent: Component<StepIconProps> = p => (
  <div class={cn('ste15', p.class)}>
    <Show
      when={p.status === 'done' && !p.icon}
      fallback={
        <Show when={p.icon} fallback={<span class="ste17">{p.index + 1}</span>}>
          {p.icon}
        </Show>
      }
    >
      <Check size={16} stroke-width={3} />
    </Show>
  </div>
);

// ─── Internal props shared across sub-components ──────────────────────────────

type InternalProps = {
  items: StepItem[];
  current: number;
  disabled: number[];
  activeIndex?: number[];
  isVertical: boolean;
  colorClass: string;
  onStepClick: (index: number) => void;
  class?: StepsProps['class'];
};

// ─── Sub-component: Default ───────────────────────────────────────────────────

const TypeDefault: Component<InternalProps> = p => (
  <div class={cn('ste01 ste02', p.colorClass, p.isVertical ? 'ste06' : 'ste05', p.class?.root)}>
    <For each={p.items}>
      {(item, i) => {
        const status = () => getStepStatus(i(), p.current, p.disabled, p.activeIndex);

        return (
          <>
            {/* Connector nằm giữa hai step (horizontal), trước mỗi step từ index 1 */}
            <Show when={!p.isVertical && i() > 0}>
              <div class={cn('ste21 ste22', `ste-s-${status()}`, p.class?.connector)} />
            </Show>

            <div
              class={cn('ste07 ste08', `ste-s-${status()}`, p.class?.step)}
              data-status={status()}
              onClick={() => status() !== 'disabled' && p.onStepClick(i())}
            >
              {/* ── Vertical: icon col + connector ── */}
              <Show when={p.isVertical}>
                <div class="ste16">
                  <StepIconContent
                    index={i()}
                    status={status()}
                    icon={item.icon}
                    class={p.class?.icon}
                  />
                  <Show when={i() < p.items.length - 1}>
                    <div class={cn('ste21 ste23', p.class?.connector)} />
                  </Show>
                </div>
              </Show>

              {/* ── Horizontal: chỉ icon (connector đã là sibling bên ngoài) ── */}
              <Show when={!p.isVertical}>
                <StepIconContent
                  index={i()}
                  status={status()}
                  icon={item.icon}
                  class={p.class?.icon}
                />
              </Show>

              {/* ── Content ── */}
              <div class="ste18">
                <Show when={item.title}>
                  <div class={cn('ste19', p.class?.title)}>{item.title}</div>
                </Show>
                <Show when={item.description}>
                  <div class={cn('ste20', p.class?.description)}>{item.description}</div>
                </Show>
              </div>
            </div>
          </>
        );
      }}
    </For>
  </div>
);

// ─── Sub-component: Navigation ────────────────────────────────────────────────

const TypeNavigation: Component<InternalProps> = p => (
  <div class={cn('ste01 ste03', p.colorClass, p.isVertical ? 'ste06' : 'ste05', p.class?.root)}>
    <For each={p.items}>
      {(item, i) => {
        const status = () => getStepStatus(i(), p.current, p.disabled, p.activeIndex);

        return (
          <>
            {/* Separator giữa các step — horizontal only */}
            <Show when={!p.isVertical && i() > 0}>
              <span class="ste11" aria-hidden="true">
                <ArrowRight
                  size={14}
                  stroke-width={3}
                  color={
                    status() === 'active' || status() === 'done' ? 'var(--color)' : 'currentColor'
                  }
                />
              </span>
            </Show>

            <div
              class={cn('ste07 ste09', `ste-s-${status()}`, p.class?.step)}
              data-status={status()}
              onClick={() => status() !== 'disabled' && p.onStepClick(i())}
            >
              <div class="ste10">
                <StepIconContent
                  index={i()}
                  status={status()}
                  icon={item.icon}
                  class={p.class?.icon}
                />
                <div class="ste18">
                  <Show when={item.title}>
                    <div class={cn('ste19', p.class?.title)}>{item.title}</div>
                  </Show>
                  <Show when={item.description}>
                    <div class={cn('ste20', p.class?.description)}>{item.description}</div>
                  </Show>
                </div>
              </div>
            </div>
          </>
        );
      }}
    </For>
  </div>
);

// ─── Sub-component: Dot ───────────────────────────────────────────────────────

const TypeDot: Component<InternalProps> = p => (
  <div class={cn('ste01 ste04', p.colorClass, p.isVertical ? 'ste06' : 'ste05', p.class?.root)}>
    <For each={p.items}>
      {(item, i) => {
        const status = () => getStepStatus(i(), p.current, p.disabled, p.activeIndex);

        return (
          <>
            {/* Connector sibling — horizontal only, trước mỗi step từ index 1 */}
            <Show when={!p.isVertical && i() > 0}>
              <div class={cn('ste21 ste22 ste24', `ste-s-${status()}`, p.class?.connector)} />
            </Show>

            <div
              class={cn('ste07 ste12', `ste-s-${status()}`, p.class?.step)}
              data-status={status()}
              onClick={() => status() !== 'disabled' && p.onStepClick(i())}
            >
              {/* ── Vertical: dot col + connector ── */}
              <Show when={p.isVertical}>
                <div class="ste13">
                  <div class={cn('ste14', p.class?.icon)} />
                  <Show when={i() < p.items.length - 1}>
                    <div class={cn('ste21 ste23', p.class?.connector)} />
                  </Show>
                </div>
              </Show>

              {/* ── Horizontal: chỉ dot (connector là sibling bên ngoài) ── */}
              <Show when={!p.isVertical}>
                <div class={cn('ste14', p.class?.icon)} />
              </Show>

              {/* Content */}
              <div class="ste18">
                <Show when={item.title}>
                  <div class={cn('ste19', p.class?.title)}>{item.title}</div>
                </Show>
                <Show when={item.description}>
                  <div class={cn('ste20', p.class?.description)}>{item.description}</div>
                </Show>
              </div>
            </div>
          </>
        );
      }}
    </For>
  </div>
);

// ─── Main Component ───────────────────────────────────────────────────────────

export const Steps: Component<StepsProps> = p => {
  p = mergeProps(
    {
      type: 'default',
      orientation: 'horizontal',
      color: 'primary',
      disabled: [],
      items: [],
    } as StepsProps,
    p,
  );

  const current = () => p.current?.() ?? 0;

  const resolvedItems = createMemo((): StepItem[] => {
    if (p.items && p.items.length > 0) return p.items;
    if (p.total && p.total > 0)
      return Array.from({ length: p.total }, (_, i) => ({ title: `Step ${i + 1}` }));
    return [];
  });

  const handleClick = (index: number) => {
    p.setCurrent?.(index);
    p.onChange?.(index);
  };

  const shared = createMemo(
    (): InternalProps => ({
      items: resolvedItems(),
      current: current(),
      disabled: p.disabled ?? [],
      activeIndex: p.activeIndex,
      isVertical: p.orientation === 'vertical',
      colorClass: getColor(p.color, 'color-primary'),
      onStepClick: handleClick,
      class: p.class,
    }),
  );

  return (
    <Show
      when={p.type === 'navigation'}
      fallback={
        <Show when={p.type === 'dot'} fallback={<TypeDefault {...shared()} />}>
          <TypeDot {...shared()} />
        </Show>
      }
    >
      <TypeNavigation {...shared()} />
    </Show>
  );
};
